  ('judicial-57f41407-moex-00244', 'judicial-57f41407', 'judicial-57f41407-moex-113-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', 'WhichofthefollowingisNOTdiscussedinthispassage?', '["Whypeopleenjoybeingwithahumorousperson", "Whatmakestheatmosphereenjoyableintheworkplace", "Howahumoristdoeshisbesttomaketheaudiencelaugh", "Wherethemostinteractiveclassintheworldcanbefound"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:37+00:00", "source_pdf_sha1": "20750a03212f", "answer_pdf_sha1": "a95b1a97355b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
