  ('judicial-57f41407-moex-00246', 'judicial-57f41407', 'judicial-57f41407-moex-113-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '於民事訴訟事件若認為法官執行職務有偏頗之虞，依民事訴訟法第33條第1項聲請法官迴避時，下 列敘述何者錯誤？', '["法官對於訴訟標的有特別利害關係，或與當事人之一造有密切之交誼或嫌怨，均屬得聲請法官迴避 的態樣", "法官進行訴訟期間安排、不就當事人聲明之證據為調查，不能認為法官執行職務有偏頗之虞", "當事人聲請法官迴避，應舉其原因，向法官所屬法院為之，並應提出能即時調查之證據釋明", "為求審判公平，縱使該訴訟事件已終結，不再繫屬該管轄之法院，聲請審理該事件之法官迴避仍具 有必要性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "5eb59e12bd0e", "answer_pdf_sha1": "fb67b130acc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00247', 'judicial-57f41407', 'judicial-57f41407-moex-113-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於管轄之規定，下列敘述何者錯誤？', '["因侵權行為涉訟者，得由行為地之法院管轄", "定法院之管轄，以判決時為準", "不動產之物權或其分割或經界涉訟者，專屬不動產所在地之法院管轄", "兩造合意定第一審管轄法院，該合意應以文書證之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "5eb59e12bd0e", "answer_pdf_sha1": "fb67b130acc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00248', 'judicial-57f41407', 'judicial-57f41407-moex-113-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於當事人適格，下列敘述何者錯誤？', '["於給付之訴，主張自己有給付請求權之人，有原告當事人適格", "於確認之訴，主張其權利法律關係存否不明之人，因有人對之為爭執，即有原告當事人適格，爭執 之人即有被告當事人適格", "由夫或妻提起離婚訴訟時，應以其配偶為被告，原告被告始有當事人適格", "以違反法定結婚年齡為由提起撤銷婚姻之訴，由配偶雙方之法定代理人起訴者，以夫或妻一方為被 告即可"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "5eb59e12bd0e", "answer_pdf_sha1": "fb67b130acc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00249', 'judicial-57f41407', 'judicial-57f41407-moex-113-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於訴訟能力，下列敘述何者錯誤？', '["16歲已婚之未成年人有訴訟能力", "訴訟能力為法院應依職權調查之訴訟要件", "訴訟能力有欠缺之人所為之訴訟行為如經法定代理人追認後，仍生效力", "非法人團體既然有當事人能力，則當然有訴訟能力"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "5eb59e12bd0e", "answer_pdf_sha1": "fb67b130acc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00250', 'judicial-57f41407', 'judicial-57f41407-moex-113-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於民事訴訟事件得否聲請訴訟參加，下列敘述何者錯誤？', '["本案訴訟裁判效力所及之第三人，該第三人私法上之地位，將因當事人之一造敗訴而受不利益，得 聲請訴訟參加", "如有道義、情感、經濟上或其他事實上之利害關係，為符合人民法感情之期待，得聲請訴訟參加", "凡對於訴訟標的之判斷或判決理由中主要爭點之認定，有法律上利害關係之第三人，得聲請訴訟參加", "第三人私法上之地位因當事人之一造敗訴，依該裁判之內容或執行結果，將致受不利益，得聲請訴 訟參加"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "5eb59e12bd0e", "answer_pdf_sha1": "fb67b130acc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00251', 'judicial-57f41407', 'judicial-57f41407-moex-113-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於訴訟標的價額之核定，下列敘述何者錯誤？', '["法院僅能依原告起訴內容核定訴訟標的價額，不得依職權調查證據", "法院核定訴訟標的價額前應讓當事人有陳述意見之機會", "訴訟標的之價額，以起訴時交易價額為準", "當事人得對法院核定訴訟標的價額之裁定提起抗告"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "5eb59e12bd0e", "answer_pdf_sha1": "fb67b130acc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00252', 'judicial-57f41407', 'judicial-57f41407-moex-113-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '如原告未於民事起訴狀簽名或蓋章，亦未記載原告國民身分證號碼，且無載明被告之住所或居所，也 未按被告人數提出繕本或影本時，下列敘述何者錯誤？', '["經審判長定期間命原告補正簽名或蓋章後仍未補正，法院得認起訴為不合程式，以裁定駁回原告之 訴", "如未依審判長之命按期補正起訴狀繕本或影本，法院得認其起訴不合程式，以裁定駁回原告之訴", "起訴狀應載明被告之住所或居所，如有欠缺，係可補正之事項，應定期間命原告補正", "國民身分證號碼雖足資特定原告之身分，仍非書狀應記載事項，縱未記載，非書狀不合程式"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "5eb59e12bd0e", "answer_pdf_sha1": "fb67b130acc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
